 * ================================================= */
void example_pipeline(void) {
    struct mq_attr a = { .mq_maxmsg = 5, .mq_msgsize = 64 };
    mqd_t q0 = mq_open("/kf_ex_p0", O_CREAT|O_RDWR, 0644, &a);
    mqd_t q1 = mq_open("/kf_ex_p1", O_CREAT|O_RDWR, 0644, &a);
    mq_send(q0, "abc", 3, 0);
    char buf[64]; ssize_t n = mq_receive(q0, buf, sizeof(buf), NULL);
    buf[n] = '\0';
    for (int i = 0; buf[i]; i++) buf[i] -= 32;
    mq_send(q1, buf, strlen(buf), 0);
    n = mq_receive(q1, buf, sizeof(buf), NULL);
    buf[n] = '\0';
    printf("Pipeline: %s\n", buf);
    mq_close(q0); mq_close(q1);
    mq_unlink("/kf_ex_p0"); mq_unlink("/kf_ex_p1");
}
